func MigrateUserData(db *sql.DB) error {
	_, err := db.Exec(`ALTER TABLE users ADD COLUMN migrated_at TIMESTAMP`)
	if err != nil {
		return fmt.Errorf("add column: %w", err)
	}
	_, err = db.Exec(`UPDATE users SET migrated_at = NOW() WHERE migrated_at IS NULL`)
	if err != nil {
		return fmt.Errorf("backfill: %w", err)
	}
	return nil
}
